                    }
                    freeLimitExhaustionBehavior = new FreeLimitExhaustionBehavior(prop.Value.GetString());
                    continue;
                }
                if (prop.NameEquals("manualCutover"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    manualCutover = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("performCutover"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    performCutover = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("encryptionProtectorAutoRotation"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    encryptionProtectorAutoRotation = prop.Value.GetBoolean();
                    continue;
                }
                if (options.Format != "W")
                {
                    additionalBinaryDataProperties.Add(prop.Name, BinaryData.FromString(prop.Value.GetRawText()));
                }
            }
            return new DatabaseUpdateProperties(
                createMode,
                collation,
                maxSizeBytes,
                sampleName,
                elasticPoolId,
                sourceDatabaseId,
                status,
                databaseId,
                createdOn,
                currentServiceObjectiveName,
                requestedServiceObjectiveName,
                defaultSecondaryLocation,
                failoverGroupId,
                restorePointInTime,
                sourceDatabaseDeletedOn,
                recoveryServicesRecoveryPointId,
                longTermRetentionBackupResourceId,
                recoverableDatabaseId,
                restorableDroppedDatabaseId,
                catalogCollation,
                isZoneRedundant,
                licenseType,
                maxLogSizeBytes,
                earliestRestoreOn,
                readScale,
                highAvailabilityReplicaCount,
                secondaryType,
                currentSku,
                autoPauseDelay,
                currentBackupStorageRedundancy,
                requestedBackupStorageRedundancy,
                minCapacity,
                pausedOn,
                resumedOn,
                maintenanceConfigurationId,
                isLedgerOn,
                isInfraEncryptionEnabled,
                federatedClientId,
                keys ?? new ChangeTrackingDictionary<string, SqlDatabaseKey>(),
                encryptionProtector,
                preferredEnclaveType,
                useFreeLimit,
                freeLimitExhaustionBehavior,
                manualCutover,
                performCutover,
                encryptionProtectorAutoRotation,
                additionalBinaryDataProperties);
        }
    }
}
